+	if len(lines) != 1 {
+		t.Fatalf("expected 1 line after scrub, got %d", len(lines))
+	}
+
+	var issue map[string]interface{}
+	json.Unmarshal(lines[0], &issue)
+	if issue["title"] != "Real Issue" {
+		t.Errorf("expected 'Real Issue', got %v", issue["title"])
+	}
+}
